namespace BgControls.Windows.Input.Touch{    public delegate void TouchEventHandler(object sender, TouchEventArgs args);    public class TouchEventArgs : RoutedEventArgs    {        private readonly System.Windows.Input.TouchEventArgs originalSystemArgs;        private readonly TouchEventArgs? originalTouchManagerArgs;        private bool isMousePromotionSuspended;        internal TouchEventArgs(RoutedEvent routedEvent, System.Windows.Input.TouchEventArgs e, object originalSource)            : base(routedEvent, originalSource)        {            this.originalSystemArgs = e;        }        internal TouchEventArgs(RoutedEvent routedEvent, BgControls.Windows.Input.Touch.TouchEventArgs e)            : base(routedEvent, e.OriginalSource)        {            this.originalSystemArgs = e.originalSystemArgs;            this.originalTouchManagerArgs = e;        }        public TouchDevice TouchDevice        {            get            {                if (this.originalTouchManagerArgs != null)                {                    return this.originalTouchManagerArgs.TouchDevice;                }                return this.originalSystemArgs.TouchDevice;            }        }        public TouchPoint GetTouchPoint(IInputElement relativeTo)        {            if (this.originalTouchManagerArgs != null)            {                return this.originalTouchManagerArgs.GetTouchPoint(relativeTo);            }            return originalSystemArgs.GetTouchPoint(relativeTo);        }        public void SuspendMousePromotionUntilTouchUp()        {            if (!this.isMousePromotionSuspended)            {                MousePromotionSuspender.SuspendMousePromotionUntilTouchUp((FrameworkElement)OriginalSource, TouchDevice.Id);                isMousePromotionSuspended = true;            }        }    }}